arguments.content:
const fs = require('fs');
const configPath = '/Users/hope/.openclaw/openclaw.json';
const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));

// 提示用户输入bot token
const botToken = process.argv[2];
if (!botToken) {
  console.log('Usage: node update_telegram_config.js <your-bot-token>');
  process.exit(1);
}

// 更新配置
config.channels.telegram.botToken = botToken;

// 保存配置
fs.writeFileSync(configPath, JSON.stringify(config, null, 2));
console.log('Telegram bot token updated successfully!');

// 重启OpenClaw
const { exec } = require('child_process');
exec('openclaw gateway restart', (error, stdout, stderr) => {
  if (error) {
    console.error(`Error restarting OpenClaw: ${error}`);
    return;
  }
  console.log('OpenClaw restarted successfully!');
});

